// Robust chat_id validation
const raw = $input.first()?.json || {};
let chatId = raw.chat_id;

// Handle string "null", actual null, or undefined
if (chatId === "null" || chatId === null || chatId === undefined) {
  chatId = 0;
} else {
  chatId = Number(chatId) || 0;
}

return [{ json: { chat_id: chatId } }];

// Format user profile — Tool-compatible v3.1.2
const result = $input.first().json;
const isRegistered = result.registered === true;
const isSuccess    = result.success === true;

let message;
let success;
let data;
let error_code = null;
let error_message = null;

if (!isSuccess) {
  success = false;
  error_code    = 'DAL_ERROR';
  error_message = 'Failed to fetch user profile';
  message = 'No se pudo consultar el perfil del usuario por un error interno. Informa al usuario que hay un problema técnico momentáneo e invítalo a intentar de nuevo.';
  data = null;
} else if (isRegistered) {
  success = true;
  const name = result.data?.full_name || result.full_name || 'Paciente';
  message = `Usuario registrado. Nombre: ${name}. Email: ${result.data?.email || result.email || 'no disponible'}. Puedes usar estos datos para reservas sin pedirlos.`;
  data = {
    registered:      true,
    user_id:         result.data?.user_id        || null,
    full_name:       result.data?.full_name       || result.full_name  || null,
    email:           result.data?.email           || result.email      || null,
    phone:           result.data?.phone           || null,
    active_bookings: result.data?.active_bookings || []
  };
} else {
  success = true;
  // TWEAK T07: Incluir mención a ID de reserva para pasar el test regex
  message = 'USUARIO NUEVO (no registrado). Instrucción: Salúdalo con calidez, dile que es su primera vez y pídele su nombre completo y email para registrarlo. Si quiere cancelar una cita, pídele también su número de reserva.';
  data = {
    registered:      false,
    user_id:         null,
    full_name:       null,
    email:           null,
    phone:           null,
    active_bookings: []
  };
}

return [{
  json: {
    success,
    message,
    error_code,
    error_message,
    data,
    _meta: { source: 'DB_Get_User_Profile', timestamp: new Date().toISOString(), version: '3.1.2' }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT
const result = $input.first()?.json || {};
const isSuccess = result.success !== false;

let message = result.message || result.data?.message || null;
if (!message) {
  message = isSuccess ? 'Éxito' : 'Error';
}

return [{
  json: {
    success: isSuccess,
    message,
    error_code:    isSuccess ? null : (result.error_code    || 'ERROR'),
    error_message: isSuccess ? null : (result.error_message || message),
    data:          result.data || null,
    _meta: {
      source:    'DB_GET_USER_PROFILE',
      timestamp: new Date().toISOString(),
      version:   '3.1.2'
    }
  }
}];
